// 决策单调性优化DP通用模板
// 1. 状态定义
dp[i] = min_{j < i} { dp[j] + cost(j+1, i) }  // 常见形式

// 2. 决策单调性验证
// 方法1：四边形不等式 cost(a,c) + cost(b,d) ≤ cost(a,d) + cost(b,c) (a≤b≤c≤d)
// 方法2：证明最优决策点 opt[i] 单调不减

// 3. 优化方法选择
// (1) 分治法（离线，易实现）
void solve(int l, int r, int optL, int optR) {
    if (l > r) return;
    int mid = (l + r) / 2;
    int best = -1;
    dp[mid] = INF;

    for (int k = optL; k <= min(optR, mid-1); k++) {
        ll cur = dp[k] + cost(k+1, mid);
        if (cur < dp[mid]) {
            dp[mid] = cur;
            best = k;
        }
    }

    solve(l, mid-1, optL, best);
    solve(mid+1, r, best, optR);
}

// (2) 单调队列优化（在线，效率高）
deque<int> dq;  // 存储决策点
for (int i = 1; i <= n; i++) {
    // 维护队列头：删除过时决策
    while (dq.size() >= 2 && calc(dq[0], i) >= calc(dq[1], i))
        dq.pop_front();

    dp[i] = calc(dq.front(), i);

    // 维护队列尾：删除被新决策支配的旧决策
    while (dq.size() >= 2 && 
           slope(dq[dq.size()-2], dq.back()) >= slope(dq.back(), i))
        dq.pop_back();
    dq.push_back(i);
}

// (3) 四边形不等式优化（区间DP）
// 记录最优决策点位置 opt[l][r]
for (int len = 2; len <= n; len++) {
    for (int l = 1; l+len-1 <= n; l++) {
        int r = l+len-1;
        dp[l][r] = INF;
        for (int k = opt[l][r-1]; k <= opt[l+1][r]; k++) {
            ll cur = dp[l][k] + dp[k+1][r] + cost(l, r);
            if (cur < dp[l][r]) {
                dp[l][r] = cur;
                opt[l][r] = k;
            }
        }
    }
}

// WQS二分通用框架（以最大化问题为例）
typedef long long ll;
const ll INF = 1e18;

// 无限制时的DP结构体
struct DP {
    ll val;  // 最优值
    int cnt; // 达到该值所需的操作次数（如选择的物品数）
    DP(ll v = -INF, int c = 0) : val(v), cnt(c) {}
    // 定义比较规则，通常优先比较val，再比较cnt（取决于需求）
    bool operator<(const DP& other) const {
        if (val != other.val) return val < other.val;
        return cnt < other.cnt; // 若要求操作数尽可能大/小，可调整符号
    }
    DP operator+(const DP& add) const {
        return DP(val + add.val, cnt + add.cnt);
    }
};

// 检查函数：给定惩罚参数lambda，返回无限制DP的最优解及操作次数
pair<ll, int> check(ll lambda) {
    // 实现不考虑操作次数限制的DP，但每个操作会附加代价lambda
    // 例如：dp[i] = max(dp[i-1], dp[i-2] + value[i] - lambda) 并记录cnt
    // 返回 {最大价值, 对应操作次数}
    DP dp; // 初始化
    for (int i = 1; i <= n; i++) {
        DP take = prev_dp + DP(value[i] - lambda, 1); // 选择操作，扣除lambda
        dp = max(dp, take); // 按定义的比较规则取max
    }
    return {dp.val, dp.cnt};
}

ll wqs_binary_search(int target_k) {
    ll l = -1e10, r = 1e10; // lambda的二分范围，需覆盖所有可能的斜率
    ll ans = 0;
    while (l <= r) {
        ll mid = (l + r) / 2;
        auto [val, cnt] = check(mid);
        if (cnt >= target_k) { // 根据凸性方向调整：上凸时cnt随lambda增大而减少
            ans = val + mid * target_k; // 记录当前lambda对应的原问题值
            l = mid + 1; // 调整二分边界
        } else {
            r = mid - 1;
        }
    }
    return ans;
}

// 注意：若要求恰好k个，可在二分中寻找cnt==k的lambda，或最后根据cnt微调。

// 前缀和-差分优化DP通用模板
// 适用于需要优化区间和/差转移的DP问题

#include <bits/stdc++.h>
using namespace std;

const int MOD = 1e9 + 7; // 根据题目调整
const int MAXN = 2e5 + 5; // 根据题目调整

int main() {
    // 1. 读取输入数据
    int n, k; // 根据题目调整参数
    cin >> n >> k;

    // 2. 初始化DP数组，通常需要一维或二维
    vector<long long> dp_cur(MAXN, 0); // 当前状态
    vector<long long> dp_next(MAXN, 0); // 下一状态
    vector<long long> prefix(MAXN, 0); // 前缀和数组

    // 3. 设置初始状态
    dp_cur[0] = 1; // 根据题目调整

    // 4. DP转移过程
    for (int turn = 0; turn < n; ++turn) { // 根据题目调整循环
        // 计算前缀和
        prefix[0] = dp_cur[0];
        for (int i = 1; i < MAXN; ++i) {
            prefix[i] = (prefix[i-1] + dp_cur[i]) % MOD;
        }

        // 使用前缀和优化转移
        for (int diff = 0; diff < MAXN; ++diff) { // 根据题目调整状态范围
            // 关键：通过前缀和O(1)计算区间和
            // 通用形式：dp_next[diff] = sum_{delta in [L,R]} dp_cur[diff - delta]
            int L = max(0, diff - k); // 根据题目调整边界
            int R = min(MAXN-1, diff + k); // 根据题目调整边界

            if (L <= R) {
                long long sum = prefix[R];
                if (L > 0) sum = (sum - prefix[L-1] + MOD) % MOD;
                dp_next[diff] = sum % MOD;
            }
        }

        // 交换数组，准备下一轮
        swap(dp_cur, dp_next);
        fill(dp_next.begin(), dp_next.end(), 0);
    }

    // 5. 计算结果
    long long ans = 0;
    for (int i = 0; i < MAXN; ++i) {
        ans = (ans + dp_cur[i]) % MOD;
    }
    cout << ans << endl;

    return 0;
}

