// 数据结构模板（以树状数组维护最大值为例）
struct Fenwick {
    int n;
    vector<int> bit;
    Fenwick(int n) : n(n), bit(n + 1, -INF) {} // 初始化为负无穷（求最大值时）
    void update(int idx, int val) {
        for (; idx <= n; idx += idx & -idx)
            bit[idx] = max(bit[idx], val);
    }
    int query(int idx) {
        int res = -INF;
        for (; idx > 0; idx -= idx & -idx)
            res = max(res, bit[idx]);
        return res;
    }
    // 若需区间查询，可扩展为线段树
};

int main() {
    // 1. 读入数据
    int n;
    cin >> n;
    vector<int> a(n);
    for (int i = 0; i < n; i++) cin >> a[i];

    // 2. 值域离散化（如果需要）
    vector<int> vals = a;
    sort(vals.begin(), vals.end());
    vals.erase(unique(vals.begin(), vals.end()), vals.end());
    auto getIdx = [&](int x) {
        return lower_bound(vals.begin(), vals.end(), x) - vals.begin() + 1; // 1-based
    };

    // 3. 初始化数据结构
    int m = vals.size();
    Fenwick ft(m);

    // 4. DP过程
    vector<int> dp(n);
    for (int i = 0; i < n; i++) {
        int idx = getIdx(a[i]);
        // 查询：例如求值小于a[i]的最大dp值
        int best = ft.query(idx - 1); // 注意边界
        dp[i] = max(1, best + 1); // 示例：LIS长度
        // 更新：将当前dp值插入数据结构
        ft.update(idx, dp[i]);
    }

    // 5. 输出答案
    int ans = *max_element(dp.begin(), dp.end());
    cout << ans << endl;

    return 0;
}

