// 李超线段树模板
struct Line {
    long long k, b;
    long long operator()(long long x) const { return k * x + b; }
};

class LiChaoTree {
    vector<Line> tree;
    vector<long long> xs;
    int n;

    void add_line(Line new_line, int node, int l, int r) {
        int mid = (l + r) / 2;
        bool left = new_line(xs[l]) < tree[node](xs[l]);
        bool middle = new_line(xs[mid]) < tree[node](xs[mid]);

        if (middle) swap(tree[node], new_line);
        if (r - l == 1) return;

        if (left != middle) {
            add_line(new_line, 2 * node + 1, l, mid);
        } else {
            add_line(new_line, 2 * node + 2, mid, r);
        }
    }

public:
    LiChaoTree(const vector<long long>& x_vals) : xs(x_vals) {
        n = xs.size();
        tree.assign(4 * n, Line{0, LLONG_MAX});
    }

    void add_line(long long k, long long b) {
        add_line(Line{k, b}, 0, 0, n);
    }

    long long query(long long x) {
        int pos = lower_bound(xs.begin(), xs.end(), x) - xs.begin();
        return query(x, 0, 0, n, pos);
    }

    long long query(long long x, int node, int l, int r, int pos) {
        long long res = tree[node](x);
        if (r - l == 1) return res;

        int mid = (l + r) / 2;
        if (pos < mid) {
            res = min(res, query(x, 2 * node + 1, l, mid, pos));
        } else {
            res = min(res, query(x, 2 * node + 2, mid, r, pos));
        }
        return res;
    }
};

