// 矩阵快速幂优化DP通用模板
#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int MOD = 1e9 + 7; // 根据题目调整模数

// 矩阵类定义
struct Matrix {
    int n, m;
    vector<vector<ll>> a;
    Matrix(int n, int m) : n(n), m(m), a(n, vector<ll>(m, 0)) {}
    Matrix operator*(const Matrix& other) const {
        assert(m == other.n);
        Matrix res(n, other.m);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < other.m; j++) {
                for (int k = 0; k < m; k++) {
                    res.a[i][j] = (res.a[i][j] + a[i][k] * other.a[k][j]) % MOD;
                }
            }
        }
        return res;
    }
};

// 矩阵快速幂
Matrix mat_pow(Matrix base, ll exp) {
    assert(base.n == base.m);
    int n = base.n;
    Matrix res(n, n);
    for (int i = 0; i < n; i++) res.a[i][i] = 1; // 单位矩阵
    while (exp > 0) {
        if (exp & 1) res = res * base;
        base = base * base;
        exp >>= 1;
    }
    return res;
}

