    // 3. 根据DP转移方程，构建转移矩阵M（维度n×n）
    // 4. 计算 M^k * F0，得到结果向量，从中提取答案
    // 5. 注意处理分段转移（如题目9）或带修改（如题目8）的情况
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    solve();
    return 0;
}

