// 多边形顶点结构体（根据题目可能需要2D或3D）
struct Point {
    ll x, y;
    Point() {}
    Point(ll _x, ll _y) : x(_x), y(_y) {}
    // 向量运算方法（叉积、点积等）
    ll cross(const Point &p) const { return x * p.y - y * p.x; }
};

Point pts[MAXN];
ll dp[MAXN][MAXN]; // dp[l][r]: 从顶点l到r形成的子多边形的分割方案数/最优值
bool valid[MAXN][MAXN]; // 验证对角线(l,r)是否合法（在简单多边形内部）

// 核心DP函数（区间DP）
ll solve(int n) {
    memset(dp, 0, sizeof(dp));
    // 初始化：相邻顶点无法形成三角形
    for (int i = 0; i < n; i++) dp[i][(i+1)%n] = 0; // 或1，根据题目定义

    // 区间长度从2到n-1（至少3个顶点才能形成三角形）
    for (int len = 2; len < n; len++) {
        for (int l = 0; l < n; l++) {
            int r = (l + len) % n;
            if (!valid[l][r]) continue; // 如果对角线(l,r)不合法则跳过

            // 枚举分割点k，形成三角形(l,k,r)
            for (int k = (l+1)%n; k != r; k = (k+1)%n) {
                if (!valid[l][k] || !valid[k][r]) continue;
                // 状态转移：根据题目要求可能是加法（计数）或取最值（最优化）
                // 计数版本：dp[l][r] += dp[l][k] * dp[k][r] （可能需要乘法原理）
                // 最优化版本：dp[l][r] = min(dp[l][r], dp[l][k] + dp[k][r] + cost(l,k,r))
                ll cost = pts[l].x * pts[k].y * pts[r].y; // 示例：1140D的权值计算
                dp[l][r] = min(dp[l][r], dp[l][k] + dp[k][r] + cost);
            }
        }
    }
    return dp[0][n-1]; // 根据题目调整返回值
}

