int n;             // 数据长度

void solve() {
    cin >> n;
    for (int i = 1; i <= n; i++) cin >> a[i];

    // 初始化DP数组
    memset(dp, 0, sizeof(dp));
    // 通常单个元素区间有基础值
    for (int i = 1; i <= n; i++) dp[i][i] = 1; // 根据题目调整

    // 区间DP标准枚举：先枚举区间长度，再枚举左端点
    for (int len = 2; len <= n; len++) {
        for (int l = 1; l + len - 1 <= n; l++) {
            int r = l + len - 1;

            // 情况1：直接合并左右两个子区间
            dp[l][r] = dp[l][r-1] + 1; // 或dp[l+1][r] + 1，根据题目

            // 情况2：枚举分割点k，将区间分成[l, k]和[k+1, r]
            for (int k = l; k < r; k++) {
                dp[l][r] = min(dp[l][r], dp[l][k] + dp[k+1][r]); // 取min或max
            }

            // 情况3：当两端点可以匹配/消除时，考虑特殊转移
            if (a[l] == a[r]) {
                // 可能需要考虑中间区间的状态
                dp[l][r] = min(dp[l][r], dp[l+1][r-1]); // 示例
            }

            // 情况4：当可以消除整个区间时（如祖玛游戏）
            // 可能需要检查区间内是否存在可消除的子结构
            for (int k = l; k < r; k++) {
                if (a[k] == a[r]) { // 示例条件
                    dp[l][r] = min(dp[l][r], dp[l][k-1] + dp[k][r]);
                }
            }
        }
    }

    cout << dp[1][n] << endl; // 输出整个区间的最优解
}

