    }
};

int main() {
    int n;
    cin >> n;
    vector<Segment> segs(n);
    for (int i = 0; i < n; ++i) {
        cin >> segs[i].l >> segs[i].r;
        segs[i].id = i;
    }

    // 1. 排序：通常按右端点升序，左端点降序
    sort(segs.begin(), segs.end());

    // 2. 离散化坐标（若值域大）
    vector<int> coords;
    for (auto& s : segs) {
        coords.push_back(s.l);
        coords.push_back(s.r);
    }
    sort(coords.begin(), coords.end());
    coords.erase(unique(coords.begin(), coords.end()), coords.end());
    auto getIdx = [&](int x) {
        return lower_bound(coords.begin(), coords.end(), x) - coords.begin();
    };

    // 3. DP定义：dp[i]表示考虑前i个区间（按排序后）的最优解
    vector<int> dp(n + 1, 0);
    // 或 dp[pos]表示覆盖到坐标pos时的最优解
    vector<int> dpCoord(coords.size() + 1, 0);

    // 4. 转移：
    //    a) 不选当前区间：dp[i] = dp[i-1]
    //    b) 选当前区间：dp[i] = max(dp[i], dp[prev] + val)
    //    其中prev是最后一个右端点小于当前左端点的区间索引
    //    可通过二分查找prev
    for (int i = 1; i <= n; ++i) {
        int l = segs[i-1].l, r = segs[i-1].r;
        // 找到右端点小于l的最后一个区间
        int lo = 0, hi = i-1;
        while (lo < hi) {
            int mid = (lo + hi + 1) / 2;
            if (segs[mid-1].r < l) lo = mid;
            else hi = mid - 1;
        }
        int prev = lo;
        dp[i] = max(dp[i-1], dp[prev] + 1); // 假设val为区间个数
        // 若区间有权值，则改为 dp[prev] + w[i]
    }

    // 5. 答案为 dp[n] 或 dpCoord.back()
    cout << dp[n] << endl;

    return 0;
}

