// 回文相关预处理函数
template<typename T>
vector<vector<bool>> preprocess_palindrome(const T &s) {
    int n = s.size();
    vector<vector<bool>> is_pal(n, vector<bool>(n, false));
    // 中心扩展法或DP预处理所有子串是否为回文
    for (int i = 0; i < n; i++) {
        // 奇数长度回文
        for (int l = i, r = i; l >= 0 && r < n && s[l] == s[r]; l--, r++) {
            is_pal[l][r] = true;
        }
        // 偶数长度回文
        for (int l = i, r = i + 1; l >= 0 && r < n && s[l] == s[r]; l--, r++) {
            is_pal[l][r] = true;
        }
    }
    return is_pal;
}

// 括号序列合法性检查
bool is_valid_bracket(const string &s) {
    int balance = 0;
    for (char c : s) {
        if (c == '(') balance++;
        else balance--;
        if (balance < 0) return false;
    }
    return balance == 0;
}

// 区间DP模板（用于括号序列计数/染色等）
void bracket_interval_dp(const string &s) {
    int n = s.size();
    vector<vector<ll>> dp(n, vector<ll>(n, 0));
    // 初始化长度为2的区间
    for (int i = 0; i < n - 1; i++) {
        if (s[i] == '(' && s[i + 1] == ')') {
            dp[i][i + 1] = 1; // 根据具体问题调整
        }
    }
    // 区间长度递增
    for (int len = 4; len <= n; len += 2) {
        for (int l = 0; l + len - 1 < n; l++) {
            int r = l + len - 1;
            if (s[l] == '(' && s[r] == ')') {
                // 情况1：最外层括号匹配
                dp[l][r] += dp[l + 1][r - 1];
            }
            // 情况2：分割成两个合法序列
            for (int k = l + 1; k < r; k += 2) {
                dp[l][r] += dp[l][k] * dp[k + 1][r];
            }
        }
    }
}

// 回文对计数模板（非重叠回文子串对）
ll count_palindrome_pairs(const string &s) {
    int n = s.size();
    auto is_pal = preprocess_palindrome(s);
    vector<int> prefix_cnt(n + 1, 0); // 前缀回文子串数
    for (int i = 0; i < n; i++) {
        prefix_cnt[i + 1] = prefix_cnt[i];
        for (int j = 0; j <= i; j++) {
            if (is_pal[j][i]) prefix_cnt[i + 1]++;
        }
    }
    ll ans = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            if (is_pal[i][j]) {
                ans += prefix_cnt[i]; // i之前的所有回文子串
            }
        }
    }
    return ans;
}

