}

// Tarjan找环（仙人掌图专用）
void tarjan(int u, int father) {
    dfn[u] = low[u] = ++dfs_clock;
    fa[u] = father;
    for (int i = head[u]; ~i; i = edges[i].next) {
        int v = edges[i].to;
        if (v == father) continue;
        if (!dfn[v]) {
            tarjan(v, u);
            low[u] = min(low[u], low[v]);
            if (low[v] > dfn[u]) {
                // 树边处理
            }
        } else if (dfn[v] < dfn[u]) {
            // 发现环
            vector<int> circle;
            int cur = u;
            while (cur != v) {
                circle.push_back(cur);
                in_circle[cur] = true;
                cur = fa[cur];
            }
            circle.push_back(v);
            in_circle[v] = true;
