// DP状态定义（示例：379G题的三维状态）
// dp[u][c][a]: 以u为根的子树，u的类型为c，子树中悬挂玩具数量为a时的最小/最大值
// 类型c通常包括：0-无玩具，1-悬挂玩具，2-特殊状态等
int dp[MAXN][3][MAXA];

// 树形DP部分（处理非环边形成的子树）
void tree_dp(int u, int father) {
    // 初始化叶子节点或基础状态
    for (int c = 0; c < 3; c++) {
        dp[u][c][0] = 0; // 根据实际情况初始化
    }

    for (int i = head[u]; ~i; i = edges[i].next) {
        int v = edges[i].to;
        if (v == father || in_circle[v]) continue; // 跳过环边
        tree_dp(v, u);

        // 合并子树DP结果
        int new_dp[3][MAXA];
        memset(new_dp, -INF, sizeof(new_dp));
        for (int cu = 0; cu < 3; cu++) {
            for (int au = 0; au <= max_a; au++) {
                if (dp[u][cu][au] < 0) continue;
                for (int cv = 0; cv < 3; cv++) {
                    for (int av = 0; av <= max_a; av++) {
                        if (dp[v][cv][av] < 0) continue;
                        // 根据题目规则合并状态
                        int ncu = cu, nau = au + av;
                        // 状态转移计算
                        new_dp[ncu][nau] = max(new_dp[ncu][nau], 
                                              dp[u][cu][au] + dp[v][cv][av]);
                    }
                }
            }
        }
        memcpy(dp[u], new_dp, sizeof(dp[u]));
    }
}

