// 通用框架：基于位mask的状态压缩DP
#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int MOD = 1e9+7;
const int MAXB = 20; // 最大位数
const int MAXMASK = (1 << MAXB);

int main() {
    // 1. 输入数据
    int n, k;
    cin >> n >> k;
    vector<int> a(n);
    for (int i = 0; i < n; i++) cin >> a[i];

    // 2. 预处理：常用高维前缀和（SOS DP）统计子集/超集信息
    vector<int> f(MAXMASK, 0);
    for (int x : a) f[x]++;
    for (int i = 0; i < MAXB; i++) {
        for (int mask = 0; mask < MAXMASK; mask++) {
            if (mask & (1 << i)) {
                f[mask] += f[mask ^ (1 << i)]; // 子集和
                // 或 f[mask ^ (1 << i)] += f[mask]; // 超集和
            }
        }
    }

    // 3. DP状态定义：dp[mask][...] 表示处理到某阶段，当前位状态为mask的方案数/最优值
    vector<vector<ll>> dp(MAXMASK, vector<ll>(k+1, 0));
    dp[0][0] = 1; // 初始状态

    // 4. DP转移：通常枚举mask、当前元素或当前位
    for (int i = 0; i < n; i++) {
        vector<vector<ll>> ndp = dp; // 滚动数组优化
        for (int mask = 0; mask < MAXMASK; mask++) {
            for (int cnt = 0; cnt < k; cnt++) {
                if (dp[mask][cnt]) {
                    int nmask = mask | a[i]; // 举例：OR操作
                    ndp[nmask][cnt+1] = (ndp[nmask][cnt+1] + dp[mask][cnt]) % MOD;
                }
            }
        }
        dp = move(ndp);
    }

    // 5. 数位DP变体：处理上界n的位限制
    auto digitDP = [&](int upper) -> ll {
        vector<vector<ll>> dp_bit(MAXB+1, vector<ll>(2, 0));
        dp_bit[0][0] = 1;
        for (int pos = 0; pos < MAXB; pos++) {
            int bit = (upper >> (MAXB-1-pos)) & 1;
            for (int tight = 0; tight <= 1; tight++) {
                if (!dp_bit[pos][tight]) continue;
                for (int cur = 0; cur <= 1; cur++) { // 当前位选0或1
                    if (tight && cur > bit) break;
                    int ntight = tight && (cur == bit);
                    dp_bit[pos+1][ntight] += dp_bit[pos][tight];
                }
            }
        }
        return dp_bit[MAXB][0] + dp_bit[MAXB][1];
    };

    // 6. 答案计算：根据问题需求聚合DP结果
    ll ans = 0;
    for (int mask = 0; mask < MAXMASK; mask++) {
        if (__builtin_popcount(mask) == k) { // 举例：要求恰好k个1
            ans = (ans + dp[mask][k]) % MOD;
        }
    }
    cout << ans << endl;

    return 0;
}
