// 状态压缩DP模板（TSP类问题）
// 通常用于求解排列相关的最优化问题，状态表示已选元素集合和最后一个元素
#include <bits/stdc++.h>
using namespace std;

const int INF = 0x3f3f3f3f;
const int MAXN = 20;  // 通常n ≤ 20（状态压缩的典型范围）

int dp[1 << MAXN][MAXN];  // dp[mask][last] 表示已选集合mask，最后一个元素是last的最优值
int cost[MAXN][MAXN];     // 元素间的转移代价
int n;                    // 元素数量

void solve() {
    // 初始化
    memset(dp, INF, sizeof(dp));
    // 初始状态：只有一个元素的情况
    for (int i = 0; i < n; i++) {
        dp[1 << i][i] = 0;  // 或根据题目设为初始代价
    }

    // 状态转移
    for (int mask = 1; mask < (1 << n); mask++) {
        for (int last = 0; last < n; last++) {
            if (!(mask & (1 << last))) continue;
            if (dp[mask][last] == INF) continue;

            // 尝试添加下一个元素
            for (int next = 0; next < n; next++) {
                if (mask & (1 << next)) continue;  // 已选过
                int new_mask = mask | (1 << next);
                // 根据题目更新代价：可能是距离、收益、兼容性等
                dp[new_mask][next] = min(dp[new_mask][next], 
                                         dp[mask][last] + cost[last][next]);
            }
        }
    }

    // 获取答案
    int ans = INF;
    int full_mask = (1 << n) - 1;
    for (int i = 0; i < n; i++) {
        ans = min(ans, dp[full_mask][i]);
    }
    // 输出答案（根据题目可能需要处理无解情况）
    cout << ans << endl;
}

