vector<vector<int>> grid; // 原始网格，可能需要预处理
vector<vector<long long>> dp; // dp[轮廓线位置][状态]
// 状态表示：用二进制位表示当前轮廓线上每个位置是否被填充/占用
// 轮廓线通常是从上到下、从左到右扫描过程中的一条分界线

void solve() {
    // 初始化dp，通常dp[0][0] = 1
    dp.assign(m + 1, vector<long long>(1 << (n + 1), 0)); // 状态大小通常与行数相关
    dp[0][0] = 1;

    for (int i = 0; i < m; i++) { // 遍历列
        for (int j = 0; j < n; j++) { // 遍历行（或按单元格遍历）
            for (int mask = 0; mask < (1 << (n + 1)); mask++) { // 遍历所有状态
                long long cur = dp[i][mask];
                if (cur == 0) continue;

                // 计算当前单元格在状态中的位置
                int pos = j; // 或根据轮廓线定义调整
                int up = (mask >> pos) & 1; // 上方格子状态
                int left = (mask >> (pos + 1)) & 1; // 左侧格子状态

                // 根据题目规则进行状态转移
                // 常见情况：
                // 1. 当前格子已被占用（如障碍物）
                if (grid[j][i] == '*') { // 假设'*'表示障碍
                    // 只能转移到未填充的状态
                    int newMask = mask & (~(1 << pos)); // 清除当前位置
                    dp[i][newMask] += cur;
                }
                // 2. 当前格子可填充
                else {
                    // 情况A: 不填充当前格子
                    int newMask = mask & (~(1 << pos));
                    dp[i][newMask] += cur;

                    // 情况B: 填充当前格子（可能需要检查与左、上格子的关系）
                    if (up == 0 && left == 0) { // 示例条件
                        newMask = mask | (1 << pos);
                        dp[i][newMask] += cur;
                    }
                }
            }
            // 可能需要滚动数组优化：dp[i] -> dp[i+1]
        }
    }

    // 最终答案通常是dp[m][0]或dp[m][特定状态]
    cout << dp[m][0] << endl;
}

