// 1. 构建自动机（AC自动机或KMP自动机）
int tr[MAXS][ALPH];    // 转移函数
int fail[MAXS];        // 失配指针
bool danger[MAXS];     // 危险状态标记（匹配到禁止模式）
int cnt = 0;           // 节点计数

void insert(string &s) {
    int p = 0;
    for (char ch : s) {
        int c = ch - 'a'; // 根据字母表调整
        if (!tr[p][c]) tr[p][c] = ++cnt;
        p = tr[p][c];
    }
    danger[p] = true; // 标记终止状态
}

void build() {
    queue<int> q;
    for (int i = 0; i < ALPH; i++) {
        if (tr[0][i]) q.push(tr[0][i]);
    }
    while (!q.empty()) {
        int u = q.front(); q.pop();
        danger[u] |= danger[fail[u]]; // 传递危险标记
        for (int i = 0; i < ALPH; i++) {
            if (tr[u][i]) {
                fail[tr[u][i]] = tr[fail[u]][i];
                q.push(tr[u][i]);
            } else {
                tr[u][i] = tr[fail[u]][i];
            }
        }
    }
}

