    vector<long long> prefix(n + 1, 0);
    for (int i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + a[i];
    }

    // 3. 预处理后缀数组（根据题目需求）
    vector<long long> suffix(n + 1, 0);
    for (int i = n - 1; i >= 0; i--) {
        suffix[i] = suffix[i + 1] + a[i];
    }

    // 4. 定义DP状态（常见形式）
    // dp_left[i]: 处理前i个元素的最优值
    // dp_right[i]: 处理从i到末尾的最优值
    vector<long long> dp_left(n + 1, 0);
    vector<long long> dp_right(n + 1, 0);

    // 5. 计算前缀DP
    for (int i = 1; i <= n; i++) {
        // 根据题目状态转移，可能涉及：
        // - 区间和（通过prefix快速计算）
        // - 维护最小值/最大值
        // - 结合其他数据结构优化
        dp_left[i] = max(dp_left[i - 1], some_calculation(i));
    }

    // 6. 计算后缀DP
    for (int i = n - 1; i >= 0; i--) {
        dp_right[i] = max(dp_right[i + 1], some_calculation(i));
    }

    // 7. 合并前后缀结果得到最终答案
    long long ans = 0;
    for (int i = 0; i <= n; i++) {
        // 常见合并方式：分割点i将数组分为[0,i)和[i,n)
        ans = max(ans, dp_left[i] + dp_right[i]);
    }

    // 8. 输出答案
    cout << ans << endl;

    return 0;
}

