const int MOD = 1e9 + 7; // 根据题目调整

int dp[MAXN]; // dp[i]表示以i为结尾/起点的最优解
vector<int> divisors[MAXN]; // 预处理每个数的约数/倍数
bool isPrime[MAXN]; // 素数筛
vector<int> primes; // 素数列表

// 预处理函数：根据题目需要选择
void preprocess(int n) {
    // 1. 预处理约数/倍数关系（用于整除图类问题）
    for (int i = 1; i <= n; i++) {
        for (int j = i * 2; j <= n; j += i) {
            divisors[j].push_back(i); // j的约数i
            // 或者 divisors[i].push_back(j); // i的倍数j
        }
    }

    // 2. 素数筛
    fill(isPrime, isPrime + n + 1, true);
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i <= n; i++) {
        if (isPrime[i]) {
            primes.push_back(i);
            for (ll j = (ll)i * i; j <= n; j += i) {
                isPrime[j] = false;
            }
        }
    }
}

int solve() {
    int n;
    cin >> n;
    vector<int> a(n);
    for (int i = 0; i < n; i++) cin >> a[i];

    // 根据题目要求排序或去重
    sort(a.begin(), a.end());

    // DP转移核心：通常有两种模式
    // 模式1：基于整除关系的DP（如题目1）
    fill(dp, dp + MAXN, 0);
    int ans = 0;
    for (int i = 0; i < n; i++) {
        int x = a[i];
        dp[x] = 1; // 初始化
        // 遍历x的所有约数
        for (int d : divisors[x]) {
            if (dp[d] > 0) {
                dp[x] = max(dp[x], dp[d] + 1);
            }
        }
        ans = max(ans, dp[x]);
    }

    // 模式2：基于素数分解或数论性质的DP
    // 通常需要结合组合数学、容斥原理等

    return ans;
}

